<?php
 namespace WPAICG\Core\Moderation; use WP_Error; if (!defined('ABSPATH')) { exit; } class AIPKit_BannedIP_Checker { public static function check(?string $client_ip, array $banned_ips_settings): ?WP_Error { if ($client_ip && !empty($banned_ips_settings['ips'])) { $banned_ips_list = array_map('trim', explode(',', $banned_ips_settings['ips'])); if (in_array($client_ip, $banned_ips_list, true)) { $banned_ip_message = $banned_ips_settings['message'] ?: __('Access from your IP address has been blocked.', 'gpt3-ai-content-generator'); return new WP_Error('ip_banned', $banned_ip_message, ['status' => 403]); } } return null; } }